return items.map(item => {
  // Zugriff auf das verschachtelte properties-Objekt von HubSpot
  const vorname = item.json.vorname || "Partner";
  const nachname = item.json.nachname || "";
  const hubspot_id = item.json.hubspot_id || "";
  const hs_persona = item.json.persona || "";

  // Content-Daten aus dem Notion-Teil des Items
  const titel = item.json.content_titel || "Strategie-Impuls";
  const einleitung = item.json.content_einleitung || "ich habe an unser Gespräch gedacht.";
  const link = item.json.content_link || "";
  const kanal = item.json.content_kanal || "Email";
  const delay = Number(item.json.task_delay || 1);

  // Nachricht zusammenbauen
  let nachricht = `Hallo ${vorname},\n\n`;
  nachricht += `${einleitung}\n\n`;
  if (link) nachricht += `Hier der Link: ${link}\n\n`;
  nachricht += `Beste Grüße,\nIhr [Ihr Name]`;

  // Fälligkeit berechnen
  const dueDate = new Date(Date.now() + delay * 24 * 60 * 60 * 1000).toISOString();

  return {
    json: {
      ...item.json, // Behält alle ursprünglichen Daten für n8n-Referenzen
      task_titel: `[${kanal}] ${titel} → ${vorname} ${nachname}`,
      task_beschreibung: nachricht,
      task_faellig: dueDate,
      task_prioritaet: "HIGH",
      hubspot_contact_id: hubspot_id,
      persona_match: hs_persona // Zum Debuggen: Hier sehen wir, was gefunden wurde
    }
  };
});

return items.map(item => {
  const p = item.json;

  // Branchen
  const branchenArray = Array.isArray(p["Ziel Branchen"])
    ? p["Ziel Branchen"]
    : (p["Ziel Branchen"] ? [p["Ziel Branchen"]] : []);

  // Personacustomer (aus Spalte "Ziel Persona")
  const personacustomerArray = Array.isArray(p["Ziel Persona"])
    ? p["Ziel Persona"]
    : (p["Ziel Persona"] ? [p["Ziel Persona"]] : []);

  // Leadstatus
  const leadstatusArray = Array.isArray(p["Ziel Leadstatus"])
    ? p["Ziel Leadstatus"]
    : (p["Ziel Leadstatus"] ? [p["Ziel Leadstatus"]] : []);

  return {
    json: {
      content_id:           p["id"] ?? "",
      content_titel:        p["Titel"] ?? "",
      content_link:         p["Link"] ?? null,
      content_einleitung:   p["Kampagnen-Einleitung"] ?? "",
      content_kanal:        p["Kanal Default"] ?? "Email",
      task_delay:           p["Task Delay (Tage)"] ?? 2,
      ziel_personacustomer_array: personacustomerArray,
      ziel_personacustomer:       personacustomerArray.join(";"),
      ziel_branche_array:         branchenArray,
      ziel_branche:               branchenArray.join(";"),
      ziel_leadstatus:             leadstatusArray.join(";")
    }
  };
});

const CONTENT_NODE_NAME = "Content - Normalisieren";
const content = $node[CONTENT_NODE_NAME].json;

// Ziel-Arrays aus Content
const zielPersonacustomer = content.ziel_personacustomer_array
  .map(p => p.toLowerCase().trim())
  .filter(p => p !== "");

const zielBranchen = content.ziel_branche_array
  .map(b => b.toLowerCase().trim())
  .filter(b => b !== "");

const zielLeadstatus = (content.ziel_leadstatus ?? "").toLowerCase().trim();

const gefiltert = items.filter(item => {
  const c = item.json;

  const personacustomer = (c.property_persona ?? "").toLowerCase().trim();
  const branche    = (c.property_branchen ?? "").toLowerCase().trim();
  const leadstatus = (c.property_leadstatus ?? "").toLowerCase().trim();
  const email      = (c.property_email    ?? "").trim();

  // Pflicht: Email vorhanden
  if (!email) return false;

  // Personacustomer Match
  // Wenn Ziel-Personacustomer leer → alle durch
  // Wenn Kontakt-Personacustomer leer → NICHT durch (kein Targeting möglich)
  const personaMatch = zielPersonacustomer.length === 0 ||
    (personacustomer !== "" && zielPersonacustomer.some(zp => personacustomer.includes(zp)));

  // Branchen Match
  // Wenn Ziel-Branche leer → alle durch
  // Wenn Kontakt-Branche leer → NICHT durch
  const brancheMatch = zielBranchen.length === 0 ||
    (branche !== "" && zielBranchen.some(zb => branche.includes(zb)));

  // Leadstatus Match
  const leadstatusMatch = zielLeadstatus === "" ||
    leadstatus === zielLeadstatus;

  return personaMatch && brancheMatch && leadstatusMatch;
});

// Debug-Output: zeigt auch warum Kontakte gefiltert wurden
if (gefiltert.length === 0) {
  // Detailanalyse für jeden Kontakt
  const diagnose = items.slice(0, 5).map(item => {
    const c = item.json;
    const personacustomer = (c.property_persona ?? "").toLowerCase().trim();
    const branche = (c.property_branchen ?? "").toLowerCase().trim();
    const leadstatus = (c.property_leadstatus ?? "").toLowerCase().trim();
    const email = (c.property_email ?? "").trim();

    const personaMatch = zielPersonacustomer.length === 0 ||
      (personacustomer !== "" && zielPersonacustomer.some(zp => personacustomer.includes(zp)));
    const brancheMatch = zielBranchen.length === 0 ||
      (branche !== "" && zielBranchen.some(zb => branche.includes(zb)));
    const leadstatusMatch = zielLeadstatus === "" || leadstatus === zielLeadstatus;

    return {
      name: c.property_name,
      email: email,
      persona_wert: personacustomer,
      branche_wert: branche,
      leadstatus_wert: leadstatus,
      personaMatch,
      brancheMatch,
      leadstatusMatch
    };
  });

  return [{
    json: {
      debug: true,
      message: "Kein Kontakt hat gematcht",
      ziel_personacustomer: zielPersonacustomer,
      ziel_branchen: zielBranchen,
      ziel_leadstatus: zielLeadstatus,
      kontakte_gesamt: items.length,
      diagnose
    }
  }];
}

return gefiltert.map(item => ({
  json: {
    hubspot_id:         item.json.property_hub_spot_id ?? "",
    vorname:            item.json.property_vorname ?? "",
    nachname:           item.json.property_nachname ?? "",
    email:              item.json.property_email ?? "",
    branche:            item.json.property_branchen ?? "",
    persona:            item.json.property_persona ?? "",
    content_id:         content.content_id,
    content_titel:      content.content_titel,
    content_link:       content.content_link,
    content_einleitung: content.content_einleitung,
    content_kanal:      content.content_kanal,
    task_delay:         content.task_delay
  }
}));
